  {
    "id": "host-can-bind-publicly-without-auth",
    "severity": "HIGH",
    "category": "security",
    "location": "scripts/ai_agent_bridge/_cli.py:762",
    "description": "The new `serve --openai` command advertises local-only tooling but accepts arbitrary `--host` values and passes them directly to `uvicorn.run` with no authentication or loopback validation. A user or wrapper can bind this proxy to `0.0.0.0`, exposing local agent CLIs and the user's Hermes/Codex/Gemini/Claude credentials/config to any network client that can reach the port. For a proxy that executes paid/local agent commands from request bodies, non-loopback binds should be rejected unless an explicit authenticated remote mode is added."
  },
  {
    "id": "prompts-leak-through-process-argv",
    "severity": "MEDIUM",
    "category": "security",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:188",
    "description": "Several backends pass the flattened user prompt as a command-line argument (`--prompt=...`, `-- ...`, or `--oneshot=...`) instead of stdin or a protected temp file. Chat prompts often contain source code, credentials, or private user data, and command-line arguments are observable via process listings by other local processes/users while the backend runs; very large prompts can also hit OS argument-length limits before the backend starts. Codex already uses stdin, and the other routes should use the same pattern or another non-argv transport."
  },
  {
    "id": "unsupported-stream-silently-ignored",
    "severity": "MEDIUM",
    "category": "spec-compliance",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:286",
    "description": "The request model allows arbitrary extra OpenAI fields, but `/v1/chat/completions` does not inspect or reject `stream: true`; it always returns a normal `chat.completion` JSON object. Many OpenAI-compatible clients switch to SSE parsing when they send `stream: true`, so silently ignoring the flag produces a protocol mismatch rather than a clear unsupported-feature error. Since Phase 1 is intentionally non-streaming, the handler should return a 400-style OpenAI error for `stream: true` until streaming is implemented."
  },
  {
    "id": "unbounded-request-fanout-to-expensive-subprocesses",
    "severity": "MEDIUM",
    "category": "dos-surface",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:299",
    "description": "Each chat completion request is flattened and immediately launches a backend CLI with up to a 120-second timeout, but there is no request body size limit, message count/content limit, or concurrency limiter around backend execution. A client can submit many large requests that consume memory during JSON parsing/prompt construction and tie up threadpool workers plus expensive agent subprocesses until timeout. Even for localhost tooling, this should have bounded input sizes and a semaphore/rate limit around subprocess launches."
  }
]

